/// <summary>
/// Extension of the <c>InventDimParm</c> table for the ETGSPAIN model.
/// </summary>
[ExtensionOf(tableStr(InventDimParm))]
final class InventDimParmETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Method for the new dimension field.
/// </summary>
/// <param name="_applicationIdFlag">Boolean value indicating the flag state.</param>
/// <returns>Returns true or false.</returns>
public NoYes parmApplicationFlag(NoYes _applicatinonIdFlag = this.getValueForDimension(classStr(ETGSPAINInventTrackingDimension_Application)))
{
    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        this.setValueForDimension(classStr(ETGSPAINInventTrackingDimension_Application), _applicatinonIdFlag);
    }
    return _applicatinonIdFlag;
}

/// <summary>
/// Returns the field ID for a specific <c>InventDimension</c>.
/// </summary>
/// <returns>Returns the field ID.</returns>
public static FieldID fieldIdApplicationId()
{

    FieldId fieldId = 0;

    if (CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        fieldId = InventDimParm::fieldIdForDimension(classStr(ETGSPAINInventTrackingDimension_Application));
    }

    return fieldId;
}
